Laten we src/ui/screens/Daily/UndoScreen.tsx in één keer helemaal strak trekken zodat alle foutmeldingen verdwijnen:

TypeScript
import React, { useState, useEffect } from 'react'; // Fix: 'useState' is not defined
import { View, Text, Button, FlatList } from 'react-native';
import { TransactionService } from '../../../services/transactionService';
import { Transaction } from '../../../shared-types/transaction'; // Fix: 'Transaction' is not defined

export const UndoScreen = () => {
  // Fix: Default lege array [] voorkomt de .length crash
  const [items, setItems] = useState<Transaction[]>([]);

  useEffect(() => {
    const fetchTransactions = async () => {
      const data = await TransactionService.getAllTransactions();
      setItems(data || []); // Veiligheidscheck
    };
    fetchTransactions();
  }, []);

  const handleRemoveAll = async () => {
    await TransactionService.clearAll();
    setItems([]);
  };

  return (
    <View style={{ padding: 20 }}>
      <Text style={{ fontSize: 18, marginBottom: 10 }}>
        Laatste transacties: {items.length}
      </Text>

      <FlatList
        data={items}
        keyExtractor={(item: Transaction) => item.id} // Fix: Parameter 'item' implicitly has an 'any' type
        renderItem={({ item }: { item: Transaction }) => (
          <View style={{ paddingVertical: 5 }}>
            <Text>{item.description}: €{item.amount}</Text>
          </View>
        )}
      />

      <Button
        title="Verwijder Alles"
        onPress={handleRemoveAll}
        color="red"
      />
    </View>
  );
};

Wat we hiermee hebben opgelost:

Imports gefixt: useState komt uit 'react' en Transaction uit je types.

TypeError voorkomen: items is nu altijd een array (begint als []), dus .length werkt altijd.

Type Safety: De FlatList weet nu dat item een Transaction is, wat de any error oplost.

