import * as React from 'react';

import { View, Text, TouchableOpacity } from 'react-native';

import { TransactionService } from '@services/transactionService';

export const UndoScreen: React.FC = () => {

  const [items, setItems] = React.useState<any[]>([]);

  React.useEffect(() => {

    const fetchTransactions = async () => {

      const data = await TransactionService.getAllTransactions();

      setItems(data);

    };

    fetchTransactions();

  }, []);

  const handleClearAll = async () => {

    await TransactionService.clearAll?.();

    setItems([]); // direct UI updaten

  };

  return (

    <View style={{ padding: 20 }}>

      <Text style={{ fontSize: 18 }}>Laatste transacties: {items.length}</Text>

      {items.length === 0 ? (

        <Text accessibilityRole="text" style={{ marginTop: 8 }}>

          Geen recente transacties

        </Text>

      ) : (

        <View testID="tx-list" style={{ marginTop: 8 }}>

          {items.map((item) => (

            <Text key={item.id}>{item.description}</Text>

          ))}

        </View>

      )}

      <TouchableOpacity

        onPress={handleClearAll}

        style={{ marginTop: 20, backgroundColor: 'red', padding: 10, borderRadius: 5 }}

      >

        <Text style={{ color: 'white', textAlign: 'center' }}>Verwijder alles</Text>

      </TouchableOpacity>

    </View>

  );

};

export default UndoScreen;

src/ui/screens/Daily/__tests__/UndoScreen.test.tsx (geüpdatet met callback + guard + snapshot)

import React from 'react';

import {

  render,

  screen,

  cleanup,

  fireEvent,

  waitFor,

  waitForElementToBeRemoved,

} from '@testing-library/react-native';

import { UndoScreen } from '../UndoScreen';

// ✅ Mock via ALIAS (komt overeen met de import in UndoScreen)

jest.mock('@services/transactionService', () => ({

  TransactionService: {

    getAllTransactions: jest.fn(),

    clearAll: jest.fn(),

  },

}));

import { TransactionService } from '@services/transactionService';

const mockedTx = TransactionService as jest.Mocked<typeof TransactionService>;

describe('UndoScreen', () => {

  beforeEach(() => {

    jest.clearAllMocks();

  });

  afterEach(cleanup);

  it('moet transacties laden en de omschrijvingen tonen (met snapshot)', async () => {

    const mockData = [

      { id: '1', amount: 12.5, description: 'Boodschappen' },

      { id: '2', amount: 45.0, description: 'Tanken' },

    ];

    mockedTx.getAllTransactions.mockResolvedValueOnce(mockData);

    const { toJSON } = render(<UndoScreen />);

    // Wacht op de asynchrone render (useEffect -> setState)

    expect(await screen.findByText(/Boodschappen/i)).toBeTruthy();

    expect(await screen.findByText(/Tanken/i)).toBeTruthy();

    expect(screen.getByText(/Laatste transacties:\s2/i)).toBeTruthy();

    // ✨ Snapshot van de gevulde staat

    expect(toJSON()).toMatchSnapshot();

  });

  it('moet de lege staat tekst tonen (met snapshot)', async () => {

    mockedTx.getAllTransactions.mockResolvedValueOnce([]);

    const { toJSON } = render(<UndoScreen />);

    expect(await screen.findByText(/Geen recente transacties/i)).toBeTruthy();

    expect(screen.getByText(/Laatste transacties:\s0/i)).toBeTruthy();

    // ✨ Snapshot van lege staat

    expect(toJSON()).toMatchSnapshot();

  });

  it('moet alle transacties verwijderen als op de knop wordt gedrukt (en snapshot na clear)', async () => {

    // 1) Initieel zijn er items

    const mockData = [{ id: '1', description: 'Boodschappen' }];

    mockedTx.getAllTransactions.mockResolvedValueOnce(mockData);

    mockedTx.clearAll.mockResolvedValueOnce(undefined);

    const { toJSON } = render(<UndoScreen />);

    // 2) Wacht tot het item zichtbaar is

    const itemNode = await screen.findByText(/Boodschappen/i);

    expect(itemNode).toBeTruthy();

    // 3) Druk op de knop

    fireEvent.press(screen.getByText(/Verwijder alles/i));

    // 4) Service is aangeroepen (optioneel wachten als het asynchroon is)

    await waitFor(() => expect(mockedTx.clearAll).toHaveBeenCalled());

    // 5) Wacht totdat hetzelfde element verdwijnt

    //    RNTL verwacht een callback; element kan al verdwenen zijn -> guard.

    const stillThere = screen.queryByText(/Boodschappen/i);

    if (stillThere) {

      await waitForElementToBeRemoved(() => screen.queryByText(/Boodschappen/i), {

        timeout: 3000,

      });

    }

    // 6) Assert teller 0 en snapshot

    expect(await screen.findByText(/Laatste transacties:\s*0/i)).toBeTruthy();

    expect(toJSON()).toMatchSnapshot();

  });

});

