De Ultieme Financiële Stress-Test

Voeg deze scenario's toe om die 100% robuustheid (en coverage!) te claimen:

TypeScript
describe('CSV Financial Accuracy (The Phoenix Standard)', () => {

  it('moet grote bedragen met duizend-scheiders correct parsen (Regel 73?)', () => {
    // Banken gebruiken vaak "1.250,50" of "1 250,50"
    const inputs = ["1.250,50", "1.000.000,00", "2.500"];
    const results = inputs.map(val => toCents(val));

    expect(results[0]).toBe(125050);     // €1.250,50
    expect(results[1]).toBe(100000000);  // €1.000.000,00
    expect(results[2]).toBe(250000);     // €2.500,00 (fallback naar hele euro's)
  });

  it('moet negatieve bedragen ("Af") absoluut omzetten naar centen', () => {
    // Sommige banken leveren "-50,00" in de kolom, anderen doen "50,00" met een "Af" label
    const input = "-10,50";
    const result = toCents(input);

    // In ons model slaan we alles positief op (de 'Af/Bij' kolom bepaalt de richting)
    // of we bewaren het negatieve teken juist wel. Check wat je model verwacht!
    expect(Math.abs(result)).toBe(1050);
  });

  it('moet omgaan met extreme precisie of corruptie (Boundary Testing)', () => {
    const inputs = [
      "0,00",       // Nul-transactie
      ",05",        // Alleen centen
      "100,",       // Alleen euro's met komma
      "undefined",  // Corrupte data
      ""            // Leeg veld
    ];

    const results = inputs.map(val => toCents(val));

    expect(results[0]).toBe(0);
    expect(results[1]).toBe(5);
    expect(results[2]).toBe(10000);
    expect(results[3]).toBe(0); // Fallback naar 0 in plaats van NaN
    expect(results[4]).toBe(0);
  });

  it('moet de "Floating Point Nightmare" voorkomen bij cumulatie', () => {
    // 0.1 + 0.2 in JS is 0.30000000000000004
    // 7x 0.70 cent is in floats vaak een probleem
    const input = Array(7).fill("0,70");
    const total = input.reduce((acc, val) => acc + toCents(val), 0);

    expect(total).toBe(490); // 7 * 70 = 490 cent exact.
  });
});

