import { renderHook } from '@testing-library/react-native';
import { useAppOrchestration } from '../useAppOrchestration';
import { createMockState } from '@test-utils/index';
import { FormProvider } from '@app/context/FormContext';
import React from 'react';

describe('useAppOrchestration', () => {
  const wrapper = ({ children, state }: any) => (
    <FormProvider initialState={state}>{children}</FormProvider>
  );

  it('moet status HYDRATING teruggeven als schemaVersion ontbreekt', () => {
    // Forceer ontbrekende schemaVersion
    const state = createMockState({ schemaVersion: '' as any });

    const { result } = renderHook(() => useAppOrchestration(), {
      wrapper: (props) => wrapper({ ...props, state })
    });

    expect(result.current.status).toBe('HYDRATING');
  });

  it('moet status ONBOARDING teruggeven bij een nieuwe gebruiker zonder data', () => {
    const state = createMockState({
      activeStep: 'LANDING',
      data: { household: { members: [] } }
    });

    const { result } = renderHook(() => useAppOrchestration(), {
      wrapper: (props) => wrapper({ ...props, state })
    });

    expect(result.current.status).toBe('ONBOARDING');
  });

  it('moet status READY teruggeven als setup voltooid is en data valide is', () => {
    const state = createMockState({
      activeStep: 'dashboard',
      isValid: true,
      data: {
        household: {
          members: [{ id: '1', name: 'Test' }]
        }
      }
    });

    const { result } = renderHook(() => useAppOrchestration(), {
      wrapper: (props) => wrapper({ ...props, state })
    });

    expect(result.current.status).toBe('READY');
  });
});

