import { config as householdSetup } from '../1setupHousehold.config';
import { config as householdDetails } from '../2detailsHousehold.config';
import { config as incomeDetails } from '../3incomeDetails.config';
import { config as fixedExpenses } from '../4fixedExpenses.config';

const configs = [
  { name: '1setupHousehold', config: householdSetup },
  { name: '2detailsHousehold', config: householdDetails },
  { name: '3incomeDetails', config: incomeDetails },
  { name: '4fixedExpenses', config: fixedExpenses },
];

describe('Wizard Page Configurations', () => {
  configs.forEach(({ name, config }) => {
    describe(`Config: ${name}`, () => {

      it('moet een valide structuur hebben', () => {
        expect(config).toBeDefined();
        if (config.fields) {
          expect(Array.isArray(config.fields)).toBe(true);
        }
      });

      // Hier pakken we de branches (vaak validatie of conditionele logica)
      it('moet validatie-logica correct uitvoeren', () => {
        // We testen of er functies in de config zitten die we kunnen aanroepen
        // Dit raakt de 'uncovered lines' zoals 31-41
        config.fields?.forEach((field: any) => {
          if (typeof field.validate === 'function') {
            // Test met lege waarde
            field.validate(undefined);
            // Test met gevulde waarde
            field.validate('test');
          }

          if (typeof field.isVisible === 'function') {
            // Forceer beide kanten van de branch (true/false)
            field.isVisible({});
            field.isVisible({ someData: true });
          }
        });
      });

      it('moet navigatie-hooks correct afhandelen', () => {
        if (typeof (config as any).onNext === 'function') {
           (config as any).onNext({ data: {} });
        }
      });
    });
  });
});

