    const onbekendeAction = { type: 'NIET_BESTAANDE_ACTIE' };
    const state = formReducer(initialState, onbekendeAction as any);

    expect(state).toBe(initialState);
  });

  it('moet validatie-status correct bijwerken via SET_VALID', () => {
    // FIX: Cast de hele actie naar any om de 'SYNC_MEMBERS' error te voorkomen
    const actie = { type: 'SET_VALID', payload: false };
    const state = formReducer({ ...initialState, isValid: true } as any, actie as any);

    expect(state.isValid).toBe(false);
  });

Wat als SET_VALID helemaal niet bestaat?

Als je na het toevoegen van as any een error krijgt dat de state niet verandert, dan heet de actie in jouw formReducer.ts waarschijnlijk anders (bijvoorbeeld VALIDATE_FORM of SET_ERROR).

