Bash
#!/usr/bin/env bash
# Phoenix Commander v3.4 – dispatcher
set -euo pipefail

PROJECT_ROOT="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
export PROJECT_ROOT
source "$PROJECT_ROOT/scripts/utils/log_bridge.sh"

# Global states
DRY_RUN=false
VERBOSE=false

# Parser voor opties
parse_args() {
    while [[ $# -gt 0 ]]; do
        case "$1" in
            -d|--dry-run) DRY_RUN=true; shift ;;
            -v|--verbose) VERBOSE=true; shift ;;
            *) break ;; # Stop bij het eerste commando (full, all, etc.)
        esac
    done
    export DRY_RUN VERBOSE
}

check_dependencies() {
  local deps=(node npm bash grep awk sed git)
  for cmd in "${deps[@]}"; do
    command -v "$cmd" >/dev/null || { log_err "Missing dependency: $cmd"; exit 40; }
  done
}

# Helper voor dry-runs
run_cmd() {
    local msg=$1
    local cmd=$2
    if [ "$DRY_RUN" = true ]; then
        log_warn "[DRY-RUN] Zou uitvoeren: $msg"
    else
        log_info "$msg"
        eval "$cmd"
    fi
}

cmd_audit() {
    log_info "🔎 Audit uitvoeren..."
    node scripts/maintenance/audit-orchestrator.js
}

cmd_test() {
    log_info "🧪 Test Suite draaien..."
    local test_cmd="npm test -- --watchAll=false"
    [ "$VERBOSE" = false ] && test_cmd="$test_cmd --silent"
    eval "$test_cmd"
}

cmd_all() {
    log_info "🚀 Volledige inspectie (Audit + Tests)..."
    cmd_audit || true
    cmd_test
}

cmd_full() {
    log_info "🌅 Starten Phoenix End-of-Day routine..."

    cmd_audit || true

    run_cmd "🧹 Linting & Formatting" "npm run lint -- --fix"

    log_info "📁 Root directory opschonen..."
    if [ "$DRY_RUN" = false ]; then
        mkdir -p scripts/temp
        find . -maxdepth 1 -name "*.sh" ! -name "phoenix.sh" -exec mv {} scripts/temp/ \;
    else
        log_warn "[DRY-RUN] Zou .sh bestanden verplaatsen naar scripts/temp/"
    fi

    cmd_test || { log_err "Tests falen! EOD afgebroken."; return 1; }

    if [ "$DRY_RUN" = false ]; then
        log_info "📦 Wijzigingen veiligstellen in Git..."
        git add .
        local grade; grade=$(grep -o 'Grade: .' reports/phoenix-audit.html 2>/dev/null | cut -d' ' -f2 || echo 'A')
        git commit -m "Phoenix EOD: $(date +'%Y-%m-%d %H:%M') - Grade $grade"
    else
        log_warn "[DRY-RUN] Zou Git commit uitvoeren met Grade info."
    fi

    log_ok "✅ Werkdag succesvol afgesloten."
}

cmd_watch() {
    log_info "👀 Watch-modus: Dashboard ververst elke 30 seconden (Ctrl+C om te stoppen)"
    while true; do
        clear
        echo "=== Phoenix Live Audit Dashboard === $(date)"
        cmd_audit || true
        sleep 30
    done
}

cmd_help() {
  cat <<HLP
Phoenix Commander v3.4
Gebruik: ./phoenix [opties] <commando>

Opties:
  -d, --dry-run    Toon wat er zou gebeuren zonder wijzigingen te maken.
  -v, --verbose    Toon alle output (inclusief volledige test logs).

Commando's:
  all        Draait zowel de Audit als de volledige Test Suite.
  full       End-of-Day run: Audit, Linting, Cleanup, Tests en Git Commit.
  audit      Draait enkel de maintenance audit rapportage.
  health     Checkt of alle systeem-dependencies aanwezig zijn.
  watch      Start een live dashboard dat de audit status herhaalt.
  rollback   Herstelt de laatste backup uit de backups/ map.
  help       Toont dit overzicht.
HLP
}

# --- Main Entry ---
check_dependencies
parse_args "$@"
# Na parse_args bevat $1 het eigenlijke commando

case "${1:-}" in
  full)     cmd_full ;;
  all)      cmd_all ;;
  audit)    cmd_audit ;;
  health)   cmd_health ;;
  watch)    cmd_watch ;;
  rollback) cmd_rollback ;;
  help|-h|--help|"") cmd_help ;;
  *) echo -e "❌ Onbekend commando: ${1}"; cmd_help; exit 1;;
esac

