1. De "Trinity" Logica in audit-orchestrator.js

We passen de berekening aan zodat hij de drie scores los berekent en als een compacte "data-string" teruggeeft aan het Bash-script.

JavaScript
// scripts/maintenance/audit-orchestrator.js
const fs = require('fs');
const path = require('path');

const isDryRun = process.env.DRY_RUN === 'true';
const isVerbose = process.env.VERBOSE === 'true';

function getTrinityData() {
    let auditScore = 85; // Je huidige basiskwaliteit
    let coverageScore = 0;
    let riskPenalty = 0;

    try {
        const coveragePath = path.join(process.cwd(), 'coverage/coverage-summary.json');
        if (fs.existsSync(coveragePath)) {
            const summary = JSON.parse(fs.readFileSync(coveragePath, 'utf8'));

            // 1. Coverage Score (Branch percentage)
            coverageScore = Math.round(summary.total.branches.pct);

            // 2. Risk Score (gebaseerd op Uncovered Lines)
            // We kijken naar het totaal aantal regels dat NIET geraakt is.
            const uncoveredLines = summary.total.lines.total - summary.total.lines.covered;
            // Penalty: elke 10 ongedekte regels is -1 punt (max -20)
            riskPenalty = Math.min(Math.round(uncoveredLines / 10), 20);
        }
    } catch (e) {
        if (isVerbose) console.warn("⚠️ Kon coverage data niet inlezen.");
    }

    const stabilityScore = Math.max(0, coverageScore - riskPenalty);
    const masterScore = Math.round((auditScore + stabilityScore) / 2);

    const getGrade = (s) => {
        if (s >= 90) return 'S';
        if (s >= 75) return 'A';
        if (s >= 60) return 'B';
        return 'C';
    };

    return {
        audit: auditScore,
        coverage: coverageScore,
        stability: stabilityScore,
        master: getGrade(masterScore)
    };
}

const scores = getTrinityData();

// Output voor phoenix.sh (één regel die we makkelijk kunnen parsen)
console.log(`TRINITY_DATA|AUDIT:${scores.audit}|COV:${scores.coverage}|STAB:${scores.stability}|MASTER:${scores.master}`);

if (isVerbose) {
    console.log(`\n--- Phoenix Trinity Report ---`);
    console.log(`🏛️ Audit Score:     ${scores.audit}%`);
    console.log(`🧪 Jest Coverage:   ${scores.coverage}%`);
    console.log(`🛡️ Stability (Net): ${scores.stability}%`);
    console.log(`👑 Master Grade:    ${scores.master}`);
}

