            riskPenalty = Math.min(Math.round(uncoveredLines / 10), 20);
        }
    } catch {
        // GEFIXED: De (e) of (_e) is volledig verwijderd.
        // In modern JavaScript (ES2019+) mag een catch blok zonder variabele.
        if (isVerbose) console.warn("⚠️ Kon coverage data niet inlezen.");
    }

// ... rest van het script ...

Waarom dit werkt:

In moderne JavaScript-omgevingen (waarin je Phoenix-omgeving draait) hoef je de fout-variabele niet meer te declareren als je er niets mee doet:

Oud: catch (e) { ... } -> Linting error indien e ongebruikt.

Nieuw: catch { ... } -> Geen variabele, dus geen linting error.

