it('moet transacties laden en de omschrijvingen tonen (met snapshot)', async () => {
  const mockData = [
    { id: '1', amount: 12.5, description: 'Boodschappen' },
    { id: '2', amount: 45.0, description: 'Tanken' },
  ];

  // Zorg dat de mock de data teruggeeft
  mockedTx.getAllTransactions.mockResolvedValueOnce(mockData);

  render(<UndoScreen />);

  // ✅ DE FIX: In plaats van een simpele regex, gebruiken we een functie
  // die kijkt of de tekst 'Boodschappen' ergens in een node voorkomt.
  // Dit lost het probleem op waarbij RN de tekst opsplitst in stukjes.
  await waitFor(() => {
    const element = screen.getByText((content, node) => {
      const hasText = (text: string) => text.includes('Boodschappen');
      const nodeHasText = hasText(content);
      const childrenDontHaveText = Array.from(node?.children || []).every(
        (child) => !hasText(typeof child === 'string' ? child : child.textContent || '')
      );
      return nodeHasText && childrenDontHaveText;
    });
    expect(element).toBeTruthy();
  });

  // Check ook de tweede
  expect(screen.getByText(/Tanken/i)).toBeTruthy();

  // Pas nu de snapshot maken
  expect(screen.toJSON()).toMatchSnapshot();
});

